// PATCH: Add local recurring-item miss audit by joining expected items to transactions.

type recurringMissingResult struct {
	RecurringID             string  `json:"recurring_id"`
	Payee                   string  `json:"payee"`
	ExpectedAmount          float64 `json:"expected_amount"`
	ExpectedDate            string  `json:"expected_date"`
	Currency                string  `json:"currency"`
	LastSeenTransactionDate string  `json:"last_seen_transaction_date"`
}

func newRecurringMissingCmd(flags *rootFlags) *cobra.Command {
	var month string
	var dbPath string
	cmd := &cobra.Command{
		Use:         "missing",
		Short:       "Find expected recurring items missing transactions this month",
		Annotations: map[string]string{"mcp:read-only": "true"},
		Example: strings.Trim(`
  # List recurring items expected in May 2026 with no matching transaction
  lunch-money-pp-cli recurring missing --month 2026-05 --json
  `, "\n"),
		RunE: func(cmd *cobra.Command, args []string) error {
			if dryRunOK(flags) {
				return nil
			}
			start, end, err := monthBounds(month)
			if err != nil {
				return usageErr(fmt.Errorf("invalid --month %q: %w", month, err))
			}
			db, err := openLocalStore(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("recurring missing: %w", err)
			}
			defer db.Close()
			results, err := buildRecurringMissing(cmd.Context(), db, start, end)
			if err != nil {
				return fmt.Errorf("recurring missing: %w", err)
			}
			w := cmd.OutOrStdout()
			if flags.asJSON {
				return json.NewEncoder(w).Encode(results)
			}
			fmt.Fprintln(w, "Recurring ID\tPayee\tExpected Amount\tExpected Date\tCurrency\tLast Seen Transaction Date")
			for _, r := range results {
				fmt.Fprintf(w, "%s\t%s\t%.2f\t%s\t%s\t%s\n",
					r.RecurringID, r.Payee, r.ExpectedAmount, r.ExpectedDate, r.Currency, r.LastSeenTransactionDate)
			}
			return nil
		},
	}
	cmd.Flags().StringVar(&month, "month", time.Now().Format("2006-01"), "Month to audit in YYYY-MM format")
	cmd.Flags().StringVar(&dbPath, "db", "", "Database path")
	return cmd
}

func buildRecurringMissing(ctx context.Context, db *store.Store, start, end time.Time) ([]recurringMissingResult, error) {
	items, err := loadResourceObjects(ctx, db, "recurring-items")
	if err != nil {
		return nil, err
	}
	txs, err := loadLocalTransactions(ctx, db)
	if err != nil {
		return nil, err
	}
	results := make([]recurringMissingResult, 0)
	for _, item := range items {
		id := localID(item, "id")
		criteria := anyMap(item["transaction_criteria"])
		expectedDate := recurringExpectedDate(item, start, end)
		if id == "" || criteria == nil || expectedDate == "" {
			continue
		}
		payee := localString(criteria, "payee")
		if payee == "" {
			payee = localString(item, "description")
		}
		amount := localFloat(criteria, "amount")
		currency := localString(criteria, "currency")
		found, lastSeen := recurringHasTransaction(txs, id, payee, amount, start, end)
		if !found {
			results = append(results, recurringMissingResult{
				RecurringID:             id,
				Payee:                   payee,
				ExpectedAmount:          amount,
				ExpectedDate:            expectedDate,
				Currency:                currency,
				LastSeenTransactionDate: lastSeen,
			})
		}
	}
	return results, nil
}

func recurringExpectedDate(item map[string]any, start, end time.Time) string {
	for _, key := range []string{"next_expected_date", "expected_date", "billing_date", "next_date"} {
		dateString := localString(item, key)
		if inMonth(dateString, start, end) {
			return dateString[:10]
		}
	}
	if matches := anyMap(item["matches"]); matches != nil {
		if expected, ok := matches["expected_occurrence_dates"].([]any); ok {
			for _, raw := range expected {
				if dateString, ok := raw.(string); ok && inMonth(dateString, start, end) {
					return dateString[:10]
				}
			}
		}
	}
	criteria := anyMap(item["transaction_criteria"])
	if criteria == nil {
		return ""
	}
	date, err := parseLocalDate(localString(criteria, "anchor_date"))
	if err != nil {
		return ""
	}
	granularity := localString(criteria, "granularity")
	// PATCH(unknown-granularity): addRecurringCadence used to silently return
	// the input on unknown granularity, leading the loops below to spin 10000
	// no-op iterations and then drop the recurring item from the report with
	// no signal. Short-circuit on unknown granularity so the row is excluded
	// deterministically and the loop is bounded by data, not by attempt count.
	if !isKnownRecurringGranularity(granularity) {
		return ""
	}
	quantity := int(localFloat(criteria, "quantity"))
	if quantity < 1 {
		quantity = 1
	}
	for i := 0; i < 10000 && date.Before(start); i++ {
		date = addRecurringCadence(date, granularity, quantity)
	}
	for i := 0; i < 10000 && date.After(end); i++ {
		date = addRecurringCadence(date, granularity, -quantity)
	}
	if !date.Before(start) && !date.After(end) {
		return date.Format("2006-01-02")
	}
	return ""
}

func inMonth(dateString string, start, end time.Time) bool {
	date, err := parseLocalDate(dateString)
	return err == nil && !date.Before(start) && !date.After(end)
}

func addRecurringCadence(date time.Time, granularity string, quantity int) time.Time {
	switch granularity {
	case "day":
		return date.AddDate(0, 0, quantity)
	case "week":
		return date.AddDate(0, 0, 7*quantity)
	case "month":
		return date.AddDate(0, quantity, 0)
	case "year":
		return date.AddDate(quantity, 0, 0)
	default:
		// Caller is expected to guard against unknown granularity via
		// isKnownRecurringGranularity — if we ever reach here it is a bug.
		return date
	}
}

func isKnownRecurringGranularity(g string) bool {
	switch g {
	case "day", "week", "month", "year":
		return true
	}
	return false
}

func recurringHasTransaction(txs []localTransaction, recurringID, payee string, amount float64, start, end time.Time) (bool, string) {
	var lastSeen time.Time
	lastSeenString := ""
	for _, tx := range txs {
		// PATCH(exclude-status): an excluded transaction must not satisfy a
		// recurring-item match. Otherwise an excluded historical row with the
		// same payee/amount would suppress a genuine missed-payment alert.
		if strings.EqualFold(tx.Status, "exclude") || strings.EqualFold(tx.Status, "excluded") {
			continue
		}
		matches := recurringTransactionMatches(tx, recurringID, payee, amount)
		if !matches {
			continue
		}
		if !tx.Date.Before(start) && !tx.Date.After(end) {
			return true, tx.DateString
		}
		if !tx.Date.After(end) && tx.Date.After(lastSeen) {
			lastSeen = tx.Date
			lastSeenString = tx.DateString
		}
	}
	return false, lastSeenString
}

func recurringTransactionMatches(tx localTransaction, recurringID, payee string, amount float64) bool {
	if tx.RecurringID != "" {
		return tx.RecurringID == recurringID
	}
	return recurringPayeeAmountMatch(tx, payee, amount)
}

func recurringPayeeAmountMatch(tx localTransaction, payee string, amount float64) bool {
	if normalizeLocalPayee(payee) == "" || tx.PayeeNormalized != normalizeLocalPayee(payee) {
		return false
	}
	tolerance := math.Abs(amount) * 0.10
	return math.Abs(tx.Amount-amount) <= tolerance
}
